function validarFortaleza(pass: string): number {
  let score = 0;
  if (pass.length >= 16) score++;
  if (/[A-Z]/.test(pass)) score++;
  if (/[a-z]/.test(pass)) score++;
  if (/[0-9]/.test(pass)) score++;
  if (/[^A-Za-z0-9]/.test(pass)) score++;
  // Penalizar patrones comunes
  if (/123|abc|qwerty|password/i.test(pass)) score -= 2;
  return Math.max(0, Math.min(score, ___));
}
